package com.socialblog.interaction.application;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.interaction.domain.*;import com.socialblog.interaction.web.CorrelationIdProvider;import org.junit.jupiter.api.Test;import java.util.UUID;import static org.assertj.core.api.Assertions.assertThat;import static org.mockito.Mockito.*;class DomainEventFactoryTest{@Test void interactionCreatedCarriesRecipient(){CorrelationIdProvider ids=mock(CorrelationIdProvider.class);when(ids.current()).thenReturn("correlation");UUID recipient=UUID.randomUUID();Interaction interaction=new Interaction(UUID.randomUUID(),TargetType.ARTICLE,UUID.randomUUID());OutboxEvent event=new DomainEventFactory(new ObjectMapper().findAndRegisterModules(),ids).created(interaction,recipient);assertThat(event.getPayload()).contains("InteractionCreated",recipient.toString(),"correlation");}}
